import React, { useMemo, useEffect } from 'react';
import { useForm, Controller, FormProvider } from 'react-hook-form';
import {
  Alert as MuiAlert,
  Box,
  Grid,
  TextField,
  Button,
  FormControlLabel,
  Checkbox,
  CircularProgress,
  Dialog,
  DialogTitle,
  DialogContent,
  IconButton,
} from '@mui/material';
import { Close as CloseIcon } from '@mui/icons-material';
import type { MarketCreateRequest, Market } from '../types/market.types';
import { useNotification } from '../contexts/NotificationContext';

// ============================================================================
// Types
// ============================================================================

/**
 * Form data type for Market
 */
export type MarketFormData = MarketCreateRequest;

/**
 * Props for MarketForm component
 */
export interface MarketFormProps {
  /** Existing market data for edit mode (optional) */
  market?: Market;
  /** Form submission handler (can be sync or async) */
  onSubmit: (data: MarketFormData) => void | Promise<void>;
  /** Cancel handler */
  onCancel: () => void;
  /** Loading state (disables form during submission) */
  isLoading?: boolean;
  /** Custom className for the form container */
  className?: string;
}

/**
 * Props for MarketFormModal component (modal wrapper)
 */
export interface MarketFormModalProps extends MarketFormProps {
  /** Whether the modal is open */
  open: boolean;
  /** Handler called when the modal requests to be closed */
  onClose: () => void;
  /** Optional title override for the modal */
  title?: string;
}


// ============================================================================
// Constants
// ============================================================================

/**
 * Default form values for creating a new market
 */
const DEFAULT_FORM_VALUES: Partial<MarketFormData> = {
  title: '',
  is_country: false,
};

// ============================================================================
// Component
// ============================================================================

/**
 * MarketForm Component
 *
 * Renders a form for creating or editing markets.
 * Uses React Hook Form with Controller pattern for form state management.
 *
 * @example
 * ```tsx
 * // Create mode
 * <MarketForm
 *   onSubmit={handleCreate}
 *   onCancel={handleCancel}
 *   isLoading={isCreating}
 * />
 *
 * // Edit mode
 * <MarketForm
 *   market={existingMarket}
 *   onSubmit={handleUpdate}
 *   onCancel={handleCancel}
 *   isLoading={isUpdating}
 * />
 * ```
 */
export function MarketForm({
  market,
  onSubmit,
  onCancel,
  isLoading = false,
  className = '',
}: MarketFormProps): React.ReactElement {
  // Determine if we're in edit mode
  const isEditMode = Boolean(market);

  // Notification context for showing success/error messages
  const { showSuccess, showError } = useNotification();

  // Build default values from existing entity or defaults
  const defaultValues = useMemo<Partial<MarketFormData>>(() => {
    if (market) {
      // Edit mode: use existing entity values
      return {
        title: market.title,
        is_country: market.is_country,
      };
    }
    // Create mode: use defaults
    return DEFAULT_FORM_VALUES;
  }, [market]);

  // Initialize React Hook Form
  const methods = useForm<MarketFormData>({
    defaultValues,
    mode: 'onBlur',
  });

  const {
    control,
    handleSubmit,
    formState: { errors },
    reset,
  } = methods;

  // Reset form when entity data changes (e.g., switching from create to edit mode)
  useEffect(() => {
    reset(defaultValues);
  }, [defaultValues, reset]);

  // Log validation errors to console for debugging
  useEffect(() => {
    if (Object.keys(errors).length > 0) {
      console.log('[MarketForm] Validation errors:', errors);
    }
  }, [errors]);
  // -------------------------------------------------------------------------
  // Form Submission
  // -------------------------------------------------------------------------

  const handleFormSubmit = async (data: MarketFormData) => {
    console.log('[MarketForm] Submitting:', { data, isEditMode });
    try {
      const result = await onSubmit(data);
      console.log('[MarketForm] Form submission successful', { data, result, isEditMode });
      // Show success notification for create operation
      if (!isEditMode) {
        showSuccess('Market created successfully');
      }
    } catch (error) {
      // Log full error details to console for debugging
      console.error('[MarketForm] Form submission failed', {
        error,
        errorMessage: error instanceof Error ? error.message : String(error),
        errorStack: error instanceof Error ? error.stack : undefined,
        data,
        isEditMode,
      });
      // Show error notification on failure
      const errorMessage = error instanceof Error ? error.message : 'An unexpected error occurred';
      showError(`Failed to ${isEditMode ? 'update' : 'create'} Market: ${errorMessage}`);
    }
  };

  // -------------------------------------------------------------------------
  // Render
  // -------------------------------------------------------------------------

  // Count validation errors
  const errorCount = Object.keys(errors).length;

  return (
    <FormProvider {...methods}>
      <Box
        component="form"
        onSubmit={handleSubmit(handleFormSubmit)}
        className={className}
        data-testid="form-market"
        noValidate
      >
        {/* Error Summary Alert */}
        {errorCount > 0 && (
          <MuiAlert
            severity="error"
            sx={{ mb: 3 }}
            data-testid="form-errors-summary"
          >
            Please fix {errorCount} error{errorCount !== 1 ? 's' : ''} before submitting
          </MuiAlert>
        )}

        <Grid container spacing={3}>
          {/* Title field */}
          <Grid size={{ xs: 12, md: 6 }}>
            {/* 4. Default: plain text field */}
            <Controller
              name="title"
              control={control}
              rules={{
                required: 'Title is required',
                maxLength: { value: 255, message: 'Title must be at most 255 characters' },
              }}
              render={({ field: formField, fieldState }) => (
                <TextField
                  {...formField}
                  label="Title"
                  fullWidth
                  required
                  disabled={isLoading}
                  error={!!fieldState.error}
                  helperText={fieldState.error?.message || "Market/sector name"}
                  placeholder=""
                  value={formField.value || ''}
                  data-testid="field-title"
                />
              )}
            />
          </Grid>

          {/* Is Country field */}
          <Grid size={{ xs: 12, md: 6 }}>
            <Controller
              name="is_country"
              control={control}
              render={({ field: formField }) => (
                <FormControlLabel
                  control={
                    <Checkbox
                      {...formField}
                      checked={formField.value ?? false}
                      onChange={(e) => formField.onChange(e.target.checked)}
                      disabled={isLoading}
                      data-testid="checkbox-is-country"
                    />
                  }
                  label="Is Country"
                />
              )}
            />
          </Grid>

          {/* Form Actions */}
          <Grid size={12}>
            <Box display="flex" gap={2} pt={2}>
              <Button
                type="submit"
                variant="contained"
                color="primary"
                disabled={isLoading}
                startIcon={isLoading ? <CircularProgress size={20} /> : undefined}
                data-testid="submit-button"
              >
                {isLoading
                  ? 'Saving...'
                  : isEditMode
                    ? 'Update Market'
                    : 'Create Market'}
              </Button>

              <Button
                type="button"
                variant="outlined"
                onClick={onCancel}
                disabled={isLoading}
                data-testid="cancel-button"
              >
                Cancel
              </Button>
            </Box>
          </Grid>
        </Grid>
      </Box>
    </FormProvider>
  );
}

// ============================================================================
// Modal Wrapper Component
// ============================================================================

/**
 * MarketFormModal Component
 *
 * Wraps the MarketForm in a Material UI Dialog for modal display.
 * Use this component when you want to show the form in a popup dialog.
 *
 * @example
 * ```tsx
 * <MarketFormModal
 *   open={isModalOpen}
 *   onClose={handleClose}
 *   onSubmit={handleCreate}
 *   onCancel={handleClose}
 *   isLoading={isCreating}
 * />
 * ```
 */
export function MarketFormModal({
  open,
  onClose,
  title,
  market,
  onSubmit,
  onCancel,
  isLoading = false,
  className = '',
}: MarketFormModalProps): React.ReactElement {
  const isEditMode = Boolean(market);
  const modalTitle = title ?? (isEditMode ? 'Edit Market' : 'Create Market');

  // Handle modal close - prevent closing during loading
  const handleClose = () => {
    if (!isLoading) {
      onClose();
    }
  };

  return (
    <Dialog
      open={open}
      onClose={handleClose}
      maxWidth="md"
      fullWidth
      data-testid="modal-market-form"
    >
      <DialogTitle sx={{ m: 0, p: 2, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        {modalTitle}
        <IconButton
          aria-label="close"
          onClick={handleClose}
          disabled={isLoading}
          data-testid="modal-close-button"
          sx={{ color: (theme) => theme.palette.grey[500] }}
        >
          <CloseIcon />
        </IconButton>
      </DialogTitle>
      <DialogContent dividers>
        <MarketForm
          market={market}
          onSubmit={onSubmit}
          onCancel={onCancel}
          isLoading={isLoading}
          className={className}
        />
      </DialogContent>
    </Dialog>
  );
}


// Default export for convenience
export default MarketForm;
